import React, { useState } from "react";
import logo from "./logo.png";

function App() {
  const [currentPage, setCurrentPage] = useState("home");

  // Function to handle navigation
  const navigateTo = (page) => {
    setCurrentPage(page);
  };

  // Home page content
  const Home = () => (
    <div style={styles.homeContainer}>
      {/* Left Section: Logo */}
      <div style={styles.logoSection}>
        <img src={logo} alt="Logo" style={styles.logo} />
      </div>

      {}
      <div style={styles.descriptionSection}>
        <nav style={styles.navbar}>
          <button style={styles.navButton} onClick={() => navigateTo("home")}>
            Home
          </button>
          <button style={styles.navButton} onClick={() => navigateTo("about")}>
            About
          </button>
          <button style={styles.navButton} onClick={() => navigateTo("contact")}>
            Contact
          </button>
          <button style={styles.navButton} onClick={() => navigateTo("login")}>
            Login
          </button>
        </nav>
        <div style={styles.descriptionContent}>
          <h1>Welcome to SoundWake</h1>
          <p>
            Our goal is to promote independent artists worldwide. Discover new underground music, create playlists, and share your
            experience with your friends.
          </p>
        </div>
      </div>
    </div>
  );

  const Login = () => {
    const [activeForm, setActiveForm] = useState("login");
    const [formData, setFormData] = useState({
      email: "",
      password: "",
      confirmPassword: "",
    });

    const handleFormSwitch = (form) => {
      setActiveForm(form);
      setFormData({ email: "", password: "", confirmPassword: "" });
    };

    const handleSubmit = (event) => {
      event.preventDefault();
      if (
        activeForm === "signup" &&
        formData.password !== formData.confirmPassword
      ) {
        alert("Passwords do not match");
        return;
      }
      alert(
        `${activeForm === "login" ? "Logged In" : "Account Created"} Successfully!`
      );
    };

    const handleInputChange = (e) => {
      const { name, value } = e.target;
      setFormData((prev) => ({ ...prev, [name]: value }));
    };

    return (
      <div style={styles.loginContainer}>
        {/* Logo */}
        <img src={logo} alt="Logo" style={styles.logoLogin} />

        {/* Back to Home */}
        <nav style={styles.navbarLogin}>
          <button
            style={styles.navButton}
            onClick={() => navigateTo("home")}
          >
            Back to Home
          </button>
        </nav>

        {/* Login Form */}
        <div style={styles.loginForm}>
          <h1>{activeForm === "login" ? "Login" : "Create Account"}</h1>
          <form onSubmit={handleSubmit} style={styles.form}>
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={formData.email}
              onChange={handleInputChange}
              style={styles.input}
              required
            />
            <input
              type="password"
              name="password"
              placeholder="Password"
              value={formData.password}
              onChange={handleInputChange}
              style={styles.input}
              required
            />
            {activeForm === "signup" && (
              <input
                type="password"
                name="confirmPassword"
                placeholder="Confirm Password"
                value={formData.confirmPassword}
                onChange={handleInputChange}
                style={styles.input}
                required
              />
            )}
            <button type="submit" style={styles.button}>
              {activeForm === "login" ? "Login" : "Sign Up"}
            </button>
          </form>
          <p style={styles.toggleText}>
            {activeForm === "login"
              ? "Don't have an account?"
              : "Already have an account?"}{" "}
            <button
              type="button"
              onClick={() =>
                handleFormSwitch(activeForm === "login" ? "signup" : "login")
              }
              style={styles.toggleButton}
            >
              {activeForm === "login" ? "Create Account" : "Login"}
            </button>
          </p>
        </div>
      </div>
    );
  };

  return (
    <div>
      {currentPage === "home" && <Home />}
      {currentPage === "login" && <Login />}
    </div>
  );
}

const styles = {
  homeContainer: {
    display: "flex",
    height: "100vh",
  },
  logoSection: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    backgroundColor: "white",
  },
  logo: {
    width: "300px",
  },
  descriptionSection: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    backgroundColor: "#0CAFFF",
    color: "black",
    fontFamily: "'Cairo', sans-serif", // Cairo font applied
  },
  navbar: {
    display: "flex",
    justifyContent: "space-around",
    backgroundColor: "#0CAFFF",
    padding: "10px",
    position: "absolute",
    top: 0,
    width: "50%",
  },
  navButton: {
    color: "black",
    backgroundColor: "transparent",
    border: "none",
    fontSize: "16px",
    cursor: "pointer",
    fontFamily: "'Cairo', sans-serif", // Cairo font applied
  },
  descriptionContent: {
    margin: "0 auto",
    maxWidth: "80%",
    textAlign: "center",
    fontFamily: "'Cairo', sans-serif", // Cairo font applied
  },
  container: {
    fontFamily: "'Cairo', sans-serif",
    maxWidth: "400px",
    margin: "0 auto",
    textAlign: "center",
    padding: "20px",
    border: "1px solid #ccc",
    borderRadius: "8px",
    boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
  },
  loginContainer: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    backgroundColor: "#7BC1FA",
    height: "100vh",
    color: "black",
    fontFamily: "'Cairo', sans-serif",
    padding: "20px",
  },
  logoLogin: {
    width: "120px",
    marginBottom: "20px",
  },
  navbarLogin: {
    display: "flex",
    justifyContent: "flex-start",
    width: "100%",
    marginBottom: "20px",
  },
  loginForm: {
    width: "80%",
    maxWidth: "400px",
    textAlign: "center",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },
  input: {
    padding: "10px",
    fontSize: "16px",
    borderRadius: "4px",
    border: "1px solid #ccc",
  },
  button: {
    padding: "10px",
    fontSize: "16px",
    backgroundColor: "#007BFF",
    color: "white",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
  },
  toggleText: {
    marginTop: "10px",
  },
  toggleButton: {
    fontSize: "16px",
    color: "#007BFF",
    background: "none",
    border: "none",
    cursor: "pointer",
  },
};

export default App;
